### Option 1: Generate a House in Blender (Python Script)

This script creates a basic house with a roof, walls, and a door using Blender's Python API.

**Instructions:**
1. Open **Blender**.
2. Go to the **Scripting** tab (top menu).
3. Click **New** to create a new text block.
4. Paste the code below into the editor.
5. Click **Run Script** (the play button ▶️).

```python
import bpy
import bmesh

# Clear existing objects
bpy.ops.object.select_all(action='SELECT')
bpy.ops.object.delete(use_global=False)

# --- Create Walls ---
# Dimensions: 10m x 10m x 4m
bpy.ops.mesh.primitive_cube_add(size=1, location=(0, 0, 2))
wall = bpy.context.active_object
wall.name = "House_Wall"
wall.scale = (10, 10, 4)

# --- Create Roof (Pyramid) ---
# We create a cone and scale it to look like a roof
bpy.ops.mesh.primitive_cone_add(radius1=0, radius2=5, depth=10, location=(0, 0, 8))
roof = bpy.context.active_object
roof.name = "House_Roof"
roof.scale = (10, 10, 1) # Flatten it to make a pyramid shape
roof.location.y = 6 # Lift it up

# --- Create Door ---
# Create a plane for the door
bpy.ops.mesh.primitive_plane_add(size=1, location=(0, 0, 2))
door = bpy.context.active_object
door.name = "Door"
door.scale = (2, 2, 0.1) # Width, Height, Thickness
door.location.x = 0
door.location.y = 4.5 # Move to the front center
door.rotation_euler = (0, 0, 0)

# --- Apply Materials (Simple Colors) ---
# Wall Material
mat_wall = bpy.data.materials.new(name="Wall_Mat")
mat_wall.use_nodes = True
bsdf = mat_wall.node_tree.nodes["Principled BSDF"]
bsdf.inputs['Base Color'].default_value = (0.8, 0.8, 0.8, 1.0) # Light Gray
wall.data.materials.append(mat_wall)

# Roof Material
mat_roof = bpy.data.materials.new(name="Roof_Mat")
mat_roof.use_nodes = True
bsdf_roof = mat_roof.node_tree.nodes["Principled BSDF"]
bsdf_roof.inputs['Base Color'].default_value = (0.6, 0.4, 0.2, 1.0) # Brown
roof.data.materials.append(mat_roof)

# Door Material
mat_door = bpy.data.materials.new(name="Door_Mat")
mat_door.use_nodes = True
bsdf_door = mat_door.node_tree.nodes["Principled BSDF"]
bsdf_door.inputs['Base Color'].default_value = (0.2, 0.1, 0.1, 1.0) # Dark Wood
door.data.materials.append(mat_door)

# --- Add Lighting ---
# Sun Light
bpy.ops.object.light_add(type='SUN', location=(10, 10, 10))
sun = bpy.context.active_object
sun.name = "Sun_Light"
sun.data.energy = 5

# Fill Light
bpy.ops.object.light_add(type='AREA', location=(-10, -10, 5))
fill = bpy.context.active_object
fill.name = "Fill_Light"
fill.data.energy = 2
fill.data.size = 5

print("House model generated successfully!")
```

### Option 2: Generate a House in Three.js (Web)

If you prefer to see the result in a web browser, you can use the following HTML/JavaScript code. This creates a simple house using Three.js primitives.

**Instructions:**
1. Create a new file on your computer named `house.html`.
2. Paste the code below into that file.
3. Open `house.html` in any modern web browser.

```html
<!DOCTYPE html>
<html>
<head>
    <title>Simple 3D House</title>
    <style>
        body { margin: 0; overflow: hidden; }
        canvas { display: block; }
    </style>
</head>
<body>
    <!-- Import Three.js from CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue

        const camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 15);
        camera.lookAt(0, 0, 0);

        const renderer = new THREE.WebGLRenderer();
        renderer.setSize(window.innerWidth, window.innerHeight);
        document.body.appendChild(renderer.domElement);

        // 2. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        scene.add(dirLight);

        // 3. Create House
        const houseGroup = new THREE.Group();

        // Walls
        const wallGeo = new THREE.BoxGeometry(10, 6, 10);
        const wallMat = new THREE.MeshStandardMaterial({ color: 0xcccccc });
        const walls = new THREE.Mesh(wallGeo, wallMat);
        houseGroup.add(walls);

        // Roof
        const roofGeo = new THREE.ConeGeometry(8, 4, 4);
        const roofMat = new THREE.MeshStandardMaterial({ color: 0x8B4513 });
        const roof = new THREE.Mesh(roofGeo, roofMat);
        roof.position.y = 7; // Lift roof
        roof.rotation.y = Math.PI / 4; // Rotate to align with walls
        houseGroup.add(roof);

        // Door
        const doorGeo = new THREE.BoxGeometry(2, 4, 0.2);
        const doorMat = new THREE.MeshStandardMaterial({ color: 0x5c4033 });
        const door = new THREE.Mesh(doorGeo, doorMat);
        door.position.set(0, 2, 5); // Front center
        houseGroup.add(door);

        // Floor
        const floorGeo = new THREE.PlaneGeometry(50, 50);
        const floorMat = new THREE.MeshStandardMaterial({ color: 0x228B22 });
        const floor = new THREE.Mesh(floorGeo, floorMat);
        floor.rotation.x = -Math.PI / 2;
        scene.add(floor);

        scene.add(houseGroup);

        // 4. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            renderer.render(scene, camera);
        }
        animate();

        // Handle window resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });
    </script>
</body>
</html>
```
